#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int val, maxVal;
        scanf("%d", &val);
        maxVal = val;
        for (int i = 1; i < 8; ++i) {
            scanf("%d", &val);
            if (val > maxVal) maxVal = val;
        }
        printf("%d\n", maxVal);
    }
    return 0;
}

